package be.schaubroeck.lpb.rkm.rekenmotor.apo;

import be.schaubroeck.lpb.rkm.rekenmotor.AbstractRekenCommand;
import be.schaubroeck.lpb.rkm.rekenmotor.LoonElement;
import be.schaubroeck.lpb.rkm.rekenmotor.RekenContext;
import be.schaubroeck.lpb.rkm.rekenmotor.keys.ContextKey;
import be.schaubroeck.lpb.rkm.rekenmotor.keys.MoneyKey;
import be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBasisRszKey;
import be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBrutoKey;
import be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenPatronaalRszKey;
import be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenRszKey;
import be.schaubroeck.lpb.rkm.rekenmotor.service.NlpGlobalService;
import be.schaubroeck.lpb.rkm.rekenmotor.util.LoonCodeManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.LoonElementManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.LoonElementManagerImp;
import be.schaubroeck.lpb.rkm.rekenmotor.util.PersoonsDataManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RekenTools;
import be.schaubroeck.lpb.tools.AardKodeExtensie;
import be.schaubroeck.lpb.tools.ApoBedrag;
import be.schaubroeck.lpb.tools.ApoHoofd;
import be.schaubroeck.lpb.tools.ApoLijn;
import be.schaubroeck.lpb.tools.Money;
import be.schaubroeck.lpb.tools.Opdracht;
import be.schaubroeck.lpb.tools.Opper;
import be.schaubroeck.lpb.tools.Persoon;
import be.schaubroeck.lpb.tools.enumtypes.AardKodeExt;
import be.schaubroeck.lpb.tools.util.AlgemeenTools;
import com.google.common.collect.HashBasedTable;
import com.google.common.collect.Table;

import java.util.ArrayList;
import java.util.Arrays;
import java.util.Collection;
import java.util.Collections;
import java.util.HashMap;
import java.util.List;
import java.util.Map;

import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.AFWIJKEND_REGIME_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.LOONCODE_MANAGER_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.LOONELEMENT_MANAGER_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.PERSOONSDATA_MANAGER_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.PERSOON_KEY;

public class VerwerkApoInput extends AbstractRekenCommand {

    public VerwerkApoInput(NlpGlobalService service) {
    }

    @Override
    protected boolean execute(RekenContext mainContext) {
        PersoonsDataManager persoonsDataManager = mainContext.getUnchecked(PERSOONSDATA_MANAGER_KEY);
        LoonCodeManager loonCodeManager = mainContext.getUnchecked(LOONCODE_MANAGER_KEY);
        List<ApoHoofd> apoHoofden = persoonsDataManager.getApoInput();
        LoonElementManager loonElementManager = new LoonElementManagerImp();
        mainContext.put(LOONELEMENT_MANAGER_KEY, loonElementManager);
        if (!apoHoofden.isEmpty()) {
            Persoon persoon = mainContext.getUnchecked(PERSOON_KEY);
            verwerkApoInput(persoon, loonElementManager, loonCodeManager, apoHoofden);

            for (Opdracht opdracht : persoon.getOpdrachten()) {
                sommeerBedragen(mainContext, opdracht);
            }
        }
        return CONTINUE_PROCESSING;
    }

    public static final List<ContextKey> APO_BEDRAG_KEYS;

    static {
        List<ContextKey> temp = new ArrayList<>();
        temp.add(RekenBrutoKey.BRUTO_MAANDLOON_KEY);
        temp.addAll(Arrays.asList(RekenBasisRszKey.values()));
        temp.addAll(Arrays.asList(RekenRszKey.values()));
        temp.addAll(Arrays.asList(RekenPatronaalRszKey.values()));
        APO_BEDRAG_KEYS = Collections.unmodifiableList(temp);

    }

    private void sommeerBedragen(RekenContext mainContext, Opdracht opdracht) {
        LoonElementManager manager = mainContext.getUnchecked(LOONELEMENT_MANAGER_KEY);
        RekenContext opdrachtContext = mainContext.getOpdrachtContext(opdracht);
        Collection<LoonElement> loonElementen = manager.getOpdrachtsElementen(opdracht);
        for (ContextKey opdrachtBedragKey : APO_BEDRAG_KEYS) {
            Money som = RekenTools.getSomProperty(opdrachtBedragKey, loonElementen);
            if (som.signum() != 0) {
                opdrachtContext.put(opdrachtBedragKey, som);
            }
        }
    }

    private void verwerkApoInput(Persoon persoon, LoonElementManager loonElementManager, LoonCodeManager loonCodeManager, List<ApoHoofd> apoHoofden) {
        Map<Integer, Opdracht> idToOpdracht = AlgemeenTools.maakIdToIdentifiableMap(persoon.getOpdrachten());
        Table<Opper, Integer, LoonElement> opperToAkeIdToLoonElementMap = HashBasedTable.create();
        Map<Integer, AardKodeExtensie> aardKodeExtensieMap = new HashMap<>();

        for (ApoHoofd hoofd : apoHoofden) {
            for (ApoLijn lijn : hoofd.getApoLijnen()) {
                Opdracht opdracht = idToOpdracht.get(hoofd.getOpdracht().getId());
                Opper opper = RekenTools.getOpperLaatsteGegevens(opdracht);
                Integer akeId = lijn.getAardKodeExtensie().getId();
                AardKodeExtensie ake = aardKodeExtensieMap.computeIfAbsent(akeId, loonCodeManager::getById);
                if (!ake.getAard().equals(AardKodeExt.I_KODE_EXT.getCode())) {
                    LoonElement element = opperToAkeIdToLoonElementMap.get(opper, akeId);
                    if (element == null) {
                        element = new LoonElement(ake);
                        opperToAkeIdToLoonElementMap.put(opper, akeId, element);
                        if (ake.getRegimeBv() != lijn.getRegimeBv()) {
                            element.putProperty(AFWIJKEND_REGIME_KEY, lijn.getRegimeBv());
                        }
                        loonElementManager.addLoonElement(element, opper);
                    }

                    for (ApoBedrag bedrag : lijn.getApoBedragen()) {
                        MoneyKey key = RekenTools.bedragTypeToMoneyKey(bedrag.getBedragType(), element.getRegimeBv(), hoofd.getDatum());
                        element.addToProperty(key, bedrag.getBedrag());
                    }
                }
            }
        }
    }

}
